{
  "name": "YE:ON (여수:연)",
  "description": "A gamified digital tourism platform for Yeosu where tourists become digital navy members of the Jeolla Left Navy.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type TabType = 'home' | 'map' | 'diary' | 'community';

export interface User {
  name: string;
  rank: string;
  affiliation: string;
  points: number;
  completedMissions: number;
}

export interface Mission {
  id: string;
  title: string;
  location: string;
  status: 'completed' | 'ongoing' | 'not-started';
  coords: { x: number, y: number };
}

export interface BongsuAlert {
  id: string;
  user: string;
  message: string;
  time: string;
  type: 'question' | 'help';
}

export interface Badge {
  id: string;
  name: string;
  icon: string;
  date: string;
}

import React, { useState } from 'react';
import { Home as HomeIcon, Map as MapIcon, BookOpen, Users, Watch, QrCode, Bell, Camera, ChevronRight, MapPin, Trophy, MessageSquare } from 'lucide-react';
import HomeView from './components/Home';
import MapView from './components/MapAR';
import DiaryView from './components/Diary';
import CommunityView from './components/Community';
import { TabType, User } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('home');

  const currentUser: User = {
    name: "이순신(Guest)",
    rank: "통제사 (명예 수군)",
    affiliation: "여수 전라좌수영",
    points: 1592,
    completedMissions: 12
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'home': return <HomeView user={currentUser} />;
      case 'map': return <MapView />;
      case 'diary': return <DiaryView />;
      case 'community': return <CommunityView />;
      default: return <HomeView user={currentUser} />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-[480px] mx-auto bg-slate-50 overflow-hidden shadow-2xl relative border-x border-slate-200">
      {/* Header */}
      <header className="px-6 py-4 flex justify-between items-center bg-white border-b border-slate-100 z-10">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-[#0F172A] rounded-lg flex items-center justify-center">
            <span className="text-white font-bold text-xs">YE</span>
          </div>
          <h1 className="text-xl font-bold tracking-tight text-[#0F172A]">
            YE<span className="text-[#EF4444]">:</span>ON
          </h1>
        </div>
        <button className="p-2 bg-slate-100 rounded-full relative">
          <Bell size={20} className="text-slate-600" />
          <span className="absolute top-1 right-1 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
        </button>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto custom-scrollbar">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className="h-20 bg-white border-t border-slate-100 flex items-center justify-around px-2 z-20 pb-safe">
        <NavButton 
          active={activeTab === 'home'} 
          onClick={() => setActiveTab('home')} 
          icon={<HomeIcon size={24} />} 
          label="홈" 
        />
        <NavButton 
          active={activeTab === 'map'} 
          onClick={() => setActiveTab('map')} 
          icon={<MapIcon size={24} />} 
          label="AR연" 
        />
        <NavButton 
          active={activeTab === 'diary'} 
          onClick={() => setActiveTab('diary')} 
          icon={<BookOpen size={24} />} 
          label="기록관" 
        />
        <NavButton 
          active={activeTab === 'community'} 
          onClick={() => setActiveTab('community')} 
          icon={<Users size={24} />} 
          label="봉수대" 
        />
      </nav>
    </div>
  );
};

interface NavButtonProps {
  active: boolean;
  onClick: () => void;
  icon: React.ReactNode;
  label: string;
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center justify-center gap-1 w-16 transition-all duration-300 ${
      active ? 'text-[#0F172A]' : 'text-slate-400'
    }`}
  >
    <div className={`p-1 rounded-xl transition-all duration-300 ${active ? 'bg-slate-100 scale-110' : ''}`}>
      {icon}
    </div>
    <span className={`text-[10px] font-medium ${active ? 'opacity-100' : 'opacity-80'}`}>{label}</span>
  </button>
);

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Camera, MapPin, X, Info, Navigation, Wind, Loader2 } from 'lucide-react';

const MapView: React.FC = () => {
  const [selectedMission, setSelectedMission] = useState<any>(null);
  const [arMode, setArMode] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isLoadingCamera, setIsLoadingCamera] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);

  const missions = [
    { id: '1', title: '진남관의 위용', location: '진남관', coords: { x: 30, y: 35 }, reward: '300냥', type: 'History' },
    { id: '2', title: '쑥라떼 보급작전', location: '여수당', coords: { x: 55, y: 50 }, reward: '100냥', type: 'Food' },
    { id: '3', title: '동백의 섬 탐사', location: '오동도', coords: { x: 80, y: 70 }, reward: '500냥', type: 'Exploration' },
  ];

  const startCamera = async () => {
    setIsLoadingCamera(true);
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment' },
        audio: false
      });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
      setArMode(true);
    } catch (err) {
      console.error("Camera access denied:", err);
      alert("카메라 권한이 필요합니다. 브라우저 설정을 확인해주세요.");
    } finally {
      setIsLoadingCamera(false);
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setArMode(false);
  };

  useEffect(() => {
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [stream]);

  if (arMode) {
    return (
      <div className="absolute inset-0 bg-black z-50 flex flex-col animate-in zoom-in-95 duration-300 overflow-hidden">
        {/* Real Camera Feed */}
        <div className="absolute inset-0 w-full h-full">
          <video
            ref={videoRef}
            autoPlay
            playsInline
            className="w-full h-full object-cover"
          />
        </div>

        {/* AR Overlay UI */}
        <div className="relative flex-1 flex flex-col pointer-events-none">
          {/* Scanning Box */}
          <div className="absolute inset-0 flex items-center justify-center p-12">
            <div className="w-full aspect-square border-2 border-dashed border-white/30 rounded-3xl relative">
              <div className="absolute top-0 left-0 w-10 h-10 border-t-4 border-l-4 border-[#EAB308] rounded-tl-2xl"></div>
              <div className="absolute top-0 right-0 w-10 h-10 border-t-4 border-r-4 border-[#EAB308] rounded-tr-2xl"></div>
              <div className="absolute bottom-0 left-0 w-10 h-10 border-b-4 border-l-4 border-[#EAB308] rounded-bl-2xl"></div>
              <div className="absolute bottom-0 right-0 w-10 h-10 border-b-4 border-r-4 border-[#EAB308] rounded-br-2xl"></div>

              {/* Virtual Kite (The AR Content) */}
              <div className="absolute inset-0 flex flex-col items-center justify-center animate-bounce pointer-events-auto">
                <div className="w-24 h-24 bg-white/20 backdrop-blur-lg rounded-2xl flex items-center justify-center border border-white/40 shadow-2xl transform rotate-12">
                  <Wind className="text-white drop-shadow-lg" size={48} />
                </div>
                <div className="mt-6 bg-[#0F172A] text-[#EAB308] text-[10px] font-black px-4 py-1.5 rounded-full shadow-2xl border border-[#EAB308]/30">
                  좌수영 전술 신호연 포착!
                </div>
              </div>

              {/* Scan Line Animation */}
              <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#EAB308] to-transparent animate-[scan_3s_ease-in-out_infinite]"></div>
            </div>
          </div>

          {/* Top Controls */}
          <div className="absolute top-8 left-0 right-0 px-6 flex justify-between items-center pointer-events-auto">
             <button 
               onClick={stopCamera}
               className="p-4 bg-[#0F172A]/80 backdrop-blur-md rounded-full text-white border border-white/10 shadow-xl"
             >
               <X size={24} />
             </button>
             <div className="bg-white/10 backdrop-blur-md px-4 py-2 rounded-2xl text-white border border-white/20 flex items-center gap-2">
               <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></div>
               <span className="text-[10px] font-bold uppercase tracking-[0.2em]">Live AR View</span>
             </div>
          </div>

          {/* Bottom Card */}
          <div className="absolute bottom-10 left-0 right-0 px-6 pointer-events-auto">
            <div className="bg-[#0F172A]/90 backdrop-blur-xl border border-[#EAB308]/20 p-6 rounded-[2.5rem] w-full shadow-2xl">
              <div className="flex items-center gap-4 mb-4">
                <div className="w-14 h-14 bg-gradient-to-br from-[#EF4444] to-[#EAB308] rounded-2xl flex items-center justify-center shadow-lg transform -rotate-3">
                  <Wind size={28} className="text-[#0F172A]" />
                </div>
                <div className="flex-1">
                  <h4 className="text-white font-bold text-lg">진남관 신호연</h4>
                  <div className="flex items-center gap-1.5">
                    <div className="w-1.5 h-1.5 bg-green-500 rounded-full"></div>
                    <p className="text-slate-400 text-[10px] font-medium tracking-wide">신호 해독률 82%... 연결 안정적</p>
                  </div>
                </div>
              </div>
              <button 
                onClick={() => { alert("축하합니다! 신호연 해독 완료. 군량미 300냥을 획득했습니다."); stopCamera(); }}
                className="w-full bg-[#EAB308] text-[#0F172A] py-4 rounded-2xl text-sm font-black shadow-xl active:scale-95 transition-all transform"
              >
                신호 해독 및 보상 획득
              </button>
            </div>
          </div>
        </div>

        <style>{`
          @keyframes scan {
            0% { top: 0%; opacity: 0; }
            50% { opacity: 1; }
            100% { top: 100%; opacity: 0; }
          }
        `}</style>
      </div>
    );
  }

  return (
    <div className="h-full relative overflow-hidden flex flex-col">
      <div className="flex-1 relative bg-slate-200">
        <div className="absolute inset-0 opacity-40" style={{backgroundImage: `radial-gradient(#0F172A 1px, transparent 1px)`, backgroundSize: '20px 20px'}}></div>

        <div className="absolute top-4 left-0 right-0 z-10 px-6 flex justify-center">
          <button 
            disabled={isLoadingCamera}
            onClick={startCamera}
            className="bg-[#0F172A] text-white px-8 py-4 rounded-full flex items-center gap-3 shadow-2xl active:scale-95 transition-all border-b-4 border-[#EF4444] disabled:opacity-50"
          >
            {isLoadingCamera ? <Loader2 className="animate-spin" size={18} /> : <Camera size={18} />}
            <span className="text-sm font-black tracking-tight">AR 카메라 켜기</span>
          </button>
        </div>

        {missions.map(mission => (
          <button
            key={mission.id}
            onClick={() => setSelectedMission(mission)}
            className="absolute p-2 transition-transform active:scale-90"
            style={{ left: `${mission.coords.x}%`, top: `${mission.coords.y}%` }}
          >
            <div className="relative">
              <div className="absolute -inset-2 bg-[#EF4444]/20 rounded-full animate-ping"></div>
              <div className="w-12 h-12 bg-white rounded-xl shadow-xl flex items-center justify-center border-2 border-[#0F172A]">
                <Wind className="text-[#0F172A]" size={24} />
              </div>
              <div className="absolute -top-1 -right-1 w-4 h-4 bg-[#EF4444] rounded-full border-2 border-white"></div>
            </div>
            <span className="absolute top-14 left-1/2 -translate-x-1/2 bg-[#0F172A] text-white text-[8px] px-2 py-0.5 rounded-full whitespace-nowrap font-bold">
              {mission.location}
            </span>
          </button>
        ))}

        {selectedMission && (
          <div className="absolute bottom-8 left-6 right-6 bg-white rounded-[2.5rem] shadow-2xl p-7 animate-in slide-in-from-bottom-8 duration-300 z-20 border border-slate-100">
            <div className="flex justify-between items-start mb-4">
              <div className="bg-blue-100 text-blue-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider">
                Mission: {selectedMission.type}
              </div>
              <button onClick={() => setSelectedMission(null)} className="p-1.5 bg-slate-100 rounded-full text-slate-400">
                <X size={16} />
              </button>
            </div>
            <h3 className="text-2xl font-black text-[#0F172A] leading-tight">{selectedMission.title}</h3>
            <p className="text-slate-500 text-xs mt-2 flex items-center gap-1">
              <MapPin size={12} className="text-red-500" /> {selectedMission.location} 부근에 신호연이 나타났습니다.
            </p>

            <div className="mt-8 flex gap-3">
              <button 
                onClick={startCamera}
                className="flex-1 bg-[#0F172A] text-white py-4 rounded-2xl font-black text-sm shadow-xl active:scale-95 transition-all"
              >
                AR 미션 시작
              </button>
              <button className="w-16 bg-slate-50 flex items-center justify-center rounded-2xl text-slate-400 border border-slate-100">
                <Navigation size={22} />
              </button>
            </div>
            <p className="text-center mt-4 text-[10px] text-slate-400 font-bold uppercase tracking-widest">성공 시 보상: {selectedMission.reward}</p>
          </div>
        )}

        <div className="absolute right-4 top-1/2 -translate-y-1/2 flex flex-col gap-3">
           <button className="w-12 h-12 bg-white shadow-xl rounded-2xl flex items-center justify-center text-[#0F172A] border border-slate-100 active:bg-slate-50">
             <Navigation size={20} />
           </button>
           <button className="w-12 h-12 bg-white shadow-xl rounded-2xl flex items-center justify-center text-[#0F172A] border border-slate-100 active:bg-slate-50">
             <Info size={20} />
           </button>
        </div>
      </div>
    </div>
  );
};

export default MapView;

import React, { useState } from 'react';
import { MessageSquare, Flame, Navigation, Send, Search, Filter, Shield, X, AlertCircle } from 'lucide-react';
import { BongsuAlert } from '../types';

const CommunityView: React.FC = () => {
  const [alerts, setAlerts] = useState<BongsuAlert[]>([
    { id: '1', user: '여수러버77', message: '진남관 근처에 주차할 곳이 마땅치 않은데 팁 있을까요?', time: '방금 전', type: 'question' },
    { id: '2', user: '바다사나이', message: '오동도 등대 가는 길에 예쁜 포토존 발견했습니다!', time: '10분 전', type: 'help' },
    { id: '3', user: '초보수군', message: '거북선 내부 입장료가 얼마인가요?', time: '25분 전', type: 'question' },
    { id: '4', user: '맛있는인생', message: '게장 골목에서 지금 대기 없는 곳 공유합니다.', time: '1시간 전', type: 'help' },
  ]);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newPost, setNewPost] = useState("");
  const [postType, setPostType] = useState<'question' | 'help'>('question');

  const handlePost = () => {
    if (!newPost.trim()) return;

    const post: BongsuAlert = {
      id: Date.now().toString(),
      user: '이순신(Guest)',
      message: newPost,
      time: '방금 전',
      type: postType
    };

    setAlerts([post, ...alerts]);
    setNewPost("");
    setIsModalOpen(false);
  };

  return (
    <div className="p-6 flex flex-col gap-6 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-24">
      {/* Search & Stats */}
      <div className="flex gap-3">
        <div className="flex-1 bg-white border border-slate-100 px-5 py-3 rounded-[1.25rem] flex items-center gap-2 shadow-sm">
          <Search size={16} className="text-slate-400" />
          <input type="text" placeholder="봉수 소식 검색..." className="bg-transparent border-none text-xs w-full focus:outline-none placeholder:text-slate-300" />
        </div>
        <button className="bg-white border border-slate-100 p-3.5 rounded-[1.25rem] shadow-sm text-slate-400 active:bg-slate-50">
          <Filter size={18} />
        </button>
      </div>

      {/* Active Beacons Feed */}
      <section>
        <div className="flex justify-between items-center mb-6">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-[#EF4444]/10 rounded-2xl flex items-center justify-center">
              <Flame size={20} className="text-[#EF4444] animate-pulse" />
            </div>
            <div>
              <h3 className="font-black text-slate-900 text-lg">실시간 봉수대</h3>
              <p className="text-[10px] text-slate-400 font-bold tracking-tight">충무공 후예들의 생생한 정보</p>
            </div>
          </div>
          <div className="flex flex-col items-end">
             <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-2 py-0.5 rounded-full">ACTIVE</span>
             <span className="text-[10px] text-slate-400 mt-1">1,240명 접속중</span>
          </div>
        </div>

        <div className="space-y-4">
          {alerts.map(alert => (
            <div key={alert.id} className="bg-white rounded-[2rem] p-6 border border-slate-100 shadow-sm animate-in slide-in-from-top-2 duration-300">
              <div className="flex justify-between items-start mb-3">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-2xl bg-slate-900 flex items-center justify-center font-black text-sm text-[#EAB308] border border-[#EAB308]/20 shadow-inner">
                    {alert.user.charAt(0)}
                  </div>
                  <div>
                    <div className="flex items-center gap-1.5">
                      <span className="text-sm font-black text-slate-900">{alert.user}</span>
                      {alert.user.includes('이순신') && <Shield size={12} className="text-blue-500 fill-blue-500" />}
                    </div>
                    <span className="text-[10px] text-slate-400 font-medium">{alert.time}</span>
                  </div>
                </div>
                <div className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-wider shadow-sm ${
                  alert.type === 'question' ? 'bg-orange-50 text-orange-600 border border-orange-100' : 'bg-emerald-50 text-emerald-600 border border-emerald-100'
                }`}>
                  {alert.type === 'question' ? '질문' : '정보공유'}
                </div>
              </div>
              <p className="text-[13px] text-slate-700 leading-relaxed font-medium">
                {alert.message}
              </p>
              <div className="mt-5 flex gap-2">
                <button className="flex-1 bg-slate-50 text-slate-600 text-[11px] font-bold py-3 rounded-2xl flex items-center justify-center gap-2 hover:bg-slate-100 transition-colors border border-slate-100">
                  <MessageSquare size={14} /> 응답하기
                </button>
                <button className="flex-1 bg-[#0F172A] text-white text-[11px] font-black py-3 rounded-2xl flex items-center justify-center gap-2 shadow-lg active:scale-95 transition-all">
                  <Navigation size={14} /> 도움주기
                </button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Write Button Floating */}
      <button 
        onClick={() => setIsModalOpen(true)}
        className="fixed bottom-28 right-6 w-16 h-16 bg-[#EF4444] rounded-full shadow-2xl shadow-red-500/30 flex items-center justify-center text-white active:scale-90 transition-all z-30 border-4 border-white"
      >
        <Send size={28} className="ml-1" />
      </button>

      {/* Post Creation Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-[#0F172A]/80 backdrop-blur-sm z-50 flex flex-col justify-end animate-in fade-in duration-300">
          <div className="bg-white rounded-t-[3rem] p-8 pb-12 animate-in slide-in-from-bottom-20 duration-500">
            <div className="flex justify-between items-center mb-8">
              <div className="flex items-center gap-3">
                <div className="w-12 h-12 bg-red-50 rounded-2xl flex items-center justify-center text-[#EF4444]">
                  <AlertCircle size={24} />
                </div>
                <div>
                  <h2 className="text-xl font-black text-slate-900">봉수 올리기</h2>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Send Signal to Navy</p>
                </div>
              </div>
              <button 
                onClick={() => setIsModalOpen(false)}
                className="p-3 bg-slate-100 rounded-full text-slate-400 active:scale-90"
              >
                <X size={20} />
              </button>
            </div>

            <div className="flex gap-2 mb-6">
              <button 
                onClick={() => setPostType('question')}
                className={`flex-1 py-3.5 rounded-2xl text-xs font-black transition-all border ${
                  postType === 'question' 
                    ? 'bg-orange-50 border-orange-200 text-orange-600 shadow-inner' 
                    : 'bg-slate-50 border-transparent text-slate-400'
                }`}
              >
                도움 요청 (질문)
              </button>
              <button 
                onClick={() => setPostType('help')}
                className={`flex-1 py-3.5 rounded-2xl text-xs font-black transition-all border ${
                  postType === 'help' 
                    ? 'bg-emerald-50 border-emerald-200 text-emerald-600 shadow-inner' 
                    : 'bg-slate-50 border-transparent text-slate-400'
                }`}
              >
                정보 공유 (제보)
              </button>
            </div>

            <textarea 
              value={newPost}
              onChange={(e) => setNewPost(e.target.value)}
              placeholder="여수 바다를 여행 중인 동료들에게 알릴 내용을 적어주세요..."
              className="w-full h-40 bg-slate-50 border border-slate-100 rounded-3xl p-6 text-sm focus:outline-none focus:ring-2 focus:ring-[#0F172A]/5 resize-none placeholder:text-slate-300 font-medium"
            />

            <button 
              onClick={handlePost}
              disabled={!newPost.trim()}
              className="w-full bg-[#0F172A] text-white py-5 rounded-2xl mt-8 font-black text-base shadow-2xl active:scale-95 transition-all disabled:opacity-50 flex items-center justify-center gap-3"
            >
              <Flame size={20} className="text-[#EF4444]" />
              봉수 발신하기
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

