              <div className="absolute bottom-0 left-0 w-10 h-10 border-b-4 border-l-4 border-[#EAB308] rounded-bl-2xl"></div>
              <div className="absolute bottom-0 right-0 w-10 h-10 border-b-4 border-r-4 border-[#EAB308] rounded-br-2xl"></div>

              {/* Virtual Kite (The AR Content) */}
              <div className="absolute inset-0 flex flex-col items-center justify-center animate-bounce pointer-events-auto">
                <div className="w-24 h-24 bg-white/20 backdrop-blur-lg rounded-2xl flex items-center justify-center border border-white/40 shadow-2xl transform rotate-12">
                  <Wind className="text-white drop-shadow-lg" size={48} />
                </div>
                <div className="mt-6 bg-[#0F172A] text-[#EAB308] text-[10px] font-black px-4 py-1.5 rounded-full shadow-2xl border border-[#EAB308]/30">
                  좌수영 전술 신호연 포착!
                </div>
              </div>

              {/* Scan Line Animation */}
              <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#EAB308] to-transparent animate-[scan_3s_ease-in-out_infinite]"></div>
            </div>
          </div>

          {/* Top Controls */}
          <div className="absolute top-8 left-0 right-0 px-6 flex justify-between items-center pointer-events-auto">
             <button 
               onClick={stopCamera}
               className="p-4 bg-[#0F172A]/80 backdrop-blur-md rounded-full text-white border border-white/10 shadow-xl"
             >
