                </div>
              </div>
              <button 
                onClick={() => { alert("축하합니다! 신호연 해독 완료. 군량미 300냥을 획득했습니다."); stopCamera(); }}
                className="w-full bg-[#EAB308] text-[#0F172A] py-4 rounded-2xl text-sm font-black shadow-xl active:scale-95 transition-all transform"
              >
